#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum CompoundAssignmentExprOperatorEnum {
    PlusEq,
    MinusEq,
    StarEq,
    SlashEq,
    PercentEq,
    AmpEq,
    PipeEq,
    CaretEq,
    LtLtEq,
    GtGtEq,
}

#[cfg(feature = "napi-bindings")]
